<template>
  <div>
    <h3 class="page-title">用户管理</h3>
    <el-table :data="users" stripe v-loading="loading">
      <el-table-column prop="id" label="ID" width="60" />
      <el-table-column prop="username" label="用户名" />
      <el-table-column prop="email" label="邮箱" />
      <el-table-column prop="role" label="角色" width="80">
        <template slot-scope="{row}">
          <el-tag :type="row.role === 'ADMIN' ? 'danger' : 'primary'" size="mini">{{ row.role }}</el-tag>
        </template>
      </el-table-column>
      <el-table-column prop="status" label="状态" width="80">
        <template slot-scope="{row}">
          <el-tag :type="row.status === 1 ? 'success' : 'danger'" size="mini">{{ row.status === 1 ? '启用' : '禁用' }}</el-tag>
        </template>
      </el-table-column>
      <el-table-column label="操作" width="120">
        <template slot-scope="{row}">
          <el-button size="mini" :type="row.status === 1 ? 'danger' : 'success'"
            @click="toggleStatus(row)" :disabled="row.role === 'ADMIN'">
            {{ row.status === 1 ? '禁用' : '启用' }}
          </el-button>
        </template>
      </el-table-column>
    </el-table>
  </div>
</template>

<script>
import { adminApi } from '../../api';
export default {
  name: 'AdminUsers',
  data() { return { users: [], loading: true }; },
  created() { this.load(); },
  methods: {
    async load() {
      this.loading = true;
      const res = await adminApi.getUsers({ page: 1, pageSize: 100 });
      if (res.code === 200) this.users = res.data.list || [];
      this.loading = false;
    },
    async toggleStatus(row) {
      await adminApi.updateUserStatus(row.id, row.status === 1 ? 0 : 1);
      this.$message.success('更新成功');
      this.load();
    }
  }
};
</script>
